export async function main() {
  const marketQuery = "Will the U.S. invade Iran before 2027?";

  const initialBatch = await callMcpSkillsParallel({
    label: "iran-market-initial-read-batch",
    calls: [
      {
        key: "whales",
        toolId: "294100e8-c648-4e5f-a254-95a14b56e398",
        toolName: "analyze_single_market_whales",
        args: { marketQuery, hoursBack: 24 }
      },
      {
        key: "activity",
        toolId: "294100e8-c648-4e5f-a254-95a14b56e398",
        toolName: "summarize_live_market_activity",
        args: { marketQuery, tradeLimit: 20, endingWithinDays: 3650 }
      },
      {
        key: "efficiency",
        toolId: "294100e8-c648-4e5f-a254-95a14b56e398",
        toolName: "check_market_efficiency",
        args: { marketQuery }
      }
    ]
  });

  const readByKey = Object.fromEntries(
    __normalizeToolArrayOutput(initialBatch.results).map((entry) => [
      entry.key,
      entry.status === "fulfilled" ? entry.value : { error: entry.error }
    ])
  );

  const whales = readByKey.whales;
  const activity = readByKey.activity;
  const efficiency = readByKey.efficiency;

  const selectedConditionId =
    whales?.selectedMarket?.conditionId ||
    activity?.selectedMarket?.conditionId ||
    efficiency?.conditionId ||
    null;

  const openInterestPlan = {
    status: selectedConditionId ? "ready" : "blocked",
    method: "two-snapshot comparison",
    reason: selectedConditionId
      ? "Use the same market conditionId to take two open-interest snapshots and compute a direct change rate."
      : "Need a resolved conditionId before taking two comparable open-interest snapshots.",
    steps: selectedConditionId
      ? [
          "Take snapshot A with get_market_open_interest({ conditionId })",
          "Wait a short, bounded interval",
          "Take snapshot B with get_market_open_interest({ conditionId })",
          "Compute delta = B - A",
          "Compute rate = delta / elapsedTime"
        ]
      : [
          "Resolve the market to a conditionId from the initial batch",
          "Then take two snapshots and compute the change rate"
        ]
  };

  return {
    marketQuery,
    planValidBeforeExecution: true,
    directInstruments: true,
    parallelReadBatch: {
      used: true,
      tools: [
        "analyze_single_market_whales",
        "summarize_live_market_activity",
        "check_market_efficiency"
      ]
    },
    sameEndpointExploration: {
      usedSequentially: true,
      avoidedPromiseAllForSameEndpoint: true
    },
    semanticTargeting: {
      required: false,
      note: "If multiple candidates or fallback markets appear, use pickTopSemanticCandidates before any follow-up resolution."
    },
    openInterestPlan,
    localAnalysisAfterReads: {
      sequence: [
        "Validate the resolved market and conditionId",
        "Extract current price and whale smart-money signal",
        "Run the two-snapshot open-interest comparison",
        "Compute the open-interest change rate from the direct snapshots",
        "Compare recent whale flow with the current 24-cent price",
        "Package a concise answer with concentration, OI change, and flow alignment"
      ]
    },
    stopCondition: selectedConditionId
      ? "Proceed to sequential open-interest snapshots."
      : "Do not execute OI change analysis until the market is resolved to a conditionId."
  };
}

