import { callMcpSkill } from "@/lib/ai/skills/mcp";

export async function main() {
  const toolId = "294100e8-c648-4e5f-a254-95a14b56e398";

  const result = await callMcpSkill({
    toolId,
    toolName: "compare_event_outcome_quotes",
    args: {
      query: "Within the 'US forces enter Iran by..?' event, compare 'US forces enter Iran by April 30?' and 'US forces enter Iran by December 31?' for clean directional execution."
    }
  });

  const outcomes = Array.isArray(result?.matchedOutcomes) ? result.matchedOutcomes : [];
  const rows = outcomes.map((o) => ({
    matchedName: o.matchedName,
    currentPrice: o.currentPrice,
    spread: o.spread,
    spreadCentsDisplay: o.spreadCentsDisplay,
    spreadPercentDisplay: o.spreadPercentDisplay,
    bestAsk: o.bestAsk,
    bestBid: o.bestBid,
