    const ap = typeof a.currentPrice === "number" ? a.currentPrice : -1;
    const bp = typeof b.currentPrice === "number" ? b.currentPrice : -1;
    return ap - bp;
  });

  const idx = sorted.findIndex((o) => {
    const name = String(o.matchedName || o.requestedName || "");
