import { callMcpSkill } from "@/lib/ai/skills/mcp";

export async function main() {
  const toolId = "294100e8-c648-4e5f-a254-95a14b56e398";

  const result = await callMcpSkill({
    toolId,
    toolName: "rank_event_tradability",
    args: {
      query: "Within the Democratic Presidential Nominee 2028 event, which candidate submarkets currently combine tight quotes with meaningful whale participation, and which ones are just illiquid headline prices?",
      eventQuery: "Democratic Presidential Nominee 2028",
      limit: 6
    }
  });

  const rankedOutcomes = Array.isArray(result?.rankedOutcomes) ? result.rankedOutcomes : [];

  const tradableNow = rankedOutcomes
    .filter((x) => x && x.classification === "tradable_now")
    .map((x) => ({
      matchedName: x.matchedName,
      conditionId: x.conditionId,
      currentPrice: x.currentPrice,
      spreadCents: x.spreadCents,
      totalDepthUsd: x.totalDepthUsd,
      whaleCount: x.whaleCount,
      whaleValue: x.whaleValue,
      tradabilityScore: x.tradabilityScore,
      classification: x.classification
    }));

  const headlineOnly = rankedOutcomes
    .filter((x) => x && x.classification === "headline_only")
    .map((x) => ({
      matchedName: x.matchedName,
      conditionId: x.conditionId,
      currentPrice: x.currentPrice,
      spreadCents: x.spreadCents,
      totalDepthUsd: x.totalDepthUsd,
      whaleCount: x.whaleCount,
      whaleValue: x.whaleValue,
      tradabilityScore: x.tradabilityScore,
      classification: x.classification
    }));

  return {
    eventTitle: result?.eventTitle,
    selectionReason: result?.selectionReason,
    bestCombinedOutcome: result?.bestCombinedOutcome,
    tradableNow,
    headlineOnly,
    analysisNotes: Array.isArray(result?.analysisNotes) ? result.analysisNotes : [],
    fetchedAt: result?.fetchedAt
  };
}

